const binary = input?.binary || {};
const fileName = String(d.media_filename || d.test_file_name || '').trim();
const mime = String(d.media_mime_type || d.test_file_mime_type || '').trim().toLowerCase();
const ext = fileName.includes('.') ? fileName.split('.').pop().toLowerCase() : '';
const hasInlineBinary = !!String(d.test_file_base64 || '').trim();
const hasBinary = !!binary.data || hasInlineBinary;
const hasSheetRows = Array.isArray(d.test_sheet_rows) && d.test_sheet_rows.length > 0;

