if (!d.chat_id) {
  error_message = 'Missing owner chat ID for bulk import.';
} else if (hasSheetRows || d.import_kind === 'google_sheet' || /docs\.google\.com\/spreadsheets/i.test(String(d.source_ref || ''))) {
  route = hasSheetRows ? 'test_sheet_rows' : 'download_sheet';
