const input = $input.first();
const base = $('Determine Worker Source').first().json || {};
const meta = $('Get WhatsApp Media Metadata').first().json || {};
return [{
  json: {
    ...base,
    media_mime_type: String(meta.mime_type || base.media_mime_type || ''),
    media_filename: String(base.media_filename || meta.file_name || base.media_id || 'owner_upload'),
    media_size: meta.file_size || null,
  },
  binary: input?.binary || {},
}];

const raw = $input.first().json || {};
const pickText = (value) => {
  if (typeof value === 'string' && value.trim()) return value.trim();
  if (Array.isArray(value)) {
    for (const entry of value) {
      const nested = pickText(entry);
      if (nested) return nested;
    }
  }
  if (value && typeof value === 'object') {
    for (const key of ['output', 'text', 'mergedResponse', 'completion', 'content', 'response', 'result']) {
      if (typeof value[key] === 'string' && value[key].trim()) return value[key].trim();
    }
    if (Array.isArray(value.content)) {
      for (const part of value.content) {
        if (typeof part?.text === 'string' && part.text.trim()) return part.text.trim();
      }
    }
  }
  return '';
};

const extractJson = (value) => {
  const text = pickText(value);
  if (!text) return null;
  try { return JSON.parse(text); } catch {}
  const block = text.match(/\{[\s\S]*\}/);
  if (block) {
    try { return JSON.parse(block[0]); } catch {}
  }
  return null;
};

const parsed = extractJson(raw) || {};
const documentConfidenceRaw = parsed.document_confidence ?? parsed.confidence ?? parsed.ocr_confidence ?? null;
const documentConfidence = documentConfidenceRaw === null || documentConfidenceRaw === undefined || documentConfidenceRaw === ''
  ? null
  : (Number(documentConfidenceRaw) > 1 && Number(documentConfidenceRaw) <= 100 ? Number(documentConfidenceRaw) / 100 : Number(documentConfidenceRaw));
const rows = Array.isArray(parsed.rows) ? parsed.rows : [];
const invalid = Array.isArray(parsed.invalid_rows) ? parsed.invalid_rows : [];
const qualityNotes = Array.isArray(parsed.quality_notes) ? parsed.quality_notes : [];
const items = [];
for (const row of rows) {
  items.push({
    json: {
      item_name: row.item_name || row.name || row.product || '',
      sku: row.sku || row.code || '',
      price: row.price,
      stock: row.stock,
      unit: row.unit || '',
      category: row.category || '',
      brand: row.brand || '',
      raw_line: row.raw_line || '',
      row_confidence: row.row_confidence ?? row.confidence ?? row.ocr_confidence ?? null,
      review_reason: row.review_reason || row.reason || '',
      needs_review: row.needs_review === true,
      document_confidence: Number.isFinite(documentConfidence) ? documentConfidence : null,
      quality_notes: qualityNotes,
    },
  });
}
for (const row of invalid) {
  items.push({
    json: {
      item_name: row.item_name || row.name || '',
      raw_line: row.raw_line || row.source || '',
      reason: row.reason || 'invalid row',
      invalid: true,
      row_confidence: row.row_confidence ?? row.confidence ?? row.ocr_confidence ?? null,
      document_confidence: Number.isFinite(documentConfidence) ? documentConfidence : null,
      quality_notes: qualityNotes,
    },
  });
}
if (!items.length) {
  items.push({ json: { invalid: true, raw_line: '', reason: 'no rows parsed', document_confidence: Number.isFinite(documentConfidence) ? documentConfidence : null, quality_notes: qualityNotes } });
}
return items;

const meta = $('Determine Worker Source').first().json || {};
const schema = $('Inspect Inventory Schema').first().json || {};
const inventory = $('Load Inventory Snapshot').all().map((item) => item.json || {}).filter((row) => row && row.item_name);
const inputRows = $input.all().map((item) => item.json || {});

const normalizeName = (value) => String(value || '').toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim().replace(/\s+/g, ' ');
const normalizeConfidence = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const num = Number(value);
  if (!Number.isFinite(num)) return null;
  if (num > 1 && num <= 100) return num / 100;
  if (num >= 0 && num <= 1) return num;
  return null;
};
const scoreCandidate = (target, candidate) => {
  const a = normalizeName(target);
  const b = normalizeName(candidate);
  if (!a || !b) return 0;
  if (a === b) return 1;
  if (b.startsWith(a) || a.startsWith(b)) return 0.9;
  if (b.includes(a) || a.includes(b)) return 0.82;
  const left = new Set(a.split(' ').filter(Boolean));
  const right = new Set(b.split(' ').filter(Boolean));
  const common = [...left].filter((word) => right.has(word)).length;
  const union = new Set([...left, ...right]).size || 1;
  return common / union;
};
const buildSku = (name, rows = [], reserved = new Set()) => {
  const used = new Set(rows.map((row) => String(row?.sku || '').trim()).filter(Boolean).map((sku) => sku.toUpperCase()));
  for (const value of reserved) used.add(String(value || '').trim().toUpperCase());
  let baseSku = normalizeName(name).toUpperCase().replace(/[^A-Z0-9]+/g, '_').replace(/^_+|_+$/g, '').slice(0, 18);
  if (!baseSku) baseSku = 'ITEM';
  let sku = baseSku;
  let suffix = 2;
  while (used.has(sku)) {
    sku = baseSku.slice(0, 14) + '_' + suffix;
    suffix += 1;
  }
  reserved.add(sku);
  return sku;
};
const mapSheetRecord = (record) => {
  const row = record && typeof record === 'object' ? record : {};
  const aliases = {};
  for (const [key, value] of Object.entries(row)) aliases[normalizeName(key)] = value;
  const get = (...keys) => {
    for (const key of keys) {
      const normalized = normalizeName(key);
      if (Object.prototype.hasOwnProperty.call(aliases, normalized)) return aliases[normalized];
    }
    return '';
  };
  const toNumber = (value) => {
    if (value === null || value === undefined || value === '') return null;
    const num = Number(String(value).replace(/,/g, '').trim());
    return Number.isFinite(num) ? num : null;
  };
  return {
    item_name: String(get('item_name', 'item name', 'name', 'product', 'product_name', 'product name') || '').trim(),
    sku: String(get('sku', 'code', 'item_code', 'item code') || '').trim(),
    price: toNumber(get('price', 'mrp', 'rate', 'selling_price', 'selling price')),
    stock: toNumber(get('stock', 'qty', 'quantity', 'inventory')),
    unit: String(get('unit', 'uom') || '').trim(),
    category: String(get('category', 'group') || '').trim(),
    brand: String(get('brand', 'company') || '').trim(),
    raw_line: JSON.stringify(row),
    row_confidence: null,
    document_confidence: null,
  };
};
const assessRow = (row, parseMode, rowThreshold) => {
  const itemName = String(row.item_name || '').trim();
  const price = row.price === null || row.price === undefined || row.price === '' ? null : Number(row.price);
  const stock = row.stock === null || row.stock === undefined || row.stock === '' ? null : Number(row.stock);
  const confidence = normalizeConfidence(row.row_confidence ?? row.confidence ?? row.ocr_confidence);
  const alphaChars = (itemName.match(/[a-z]/gi) || []).length;
  const digitChars = (itemName.match(/\d/g) || []).length;
  const reasons = [];
  if (!itemName) reasons.push('missing item name');
  if (price === null || Number.isNaN(price) || price <= 0) reasons.push('missing or invalid price');
  if (stock === null || Number.isNaN(stock) || stock < 0) reasons.push('missing or invalid stock');
  if (parseMode !== 'sheet') {
    if (confidence === null) reasons.push('missing OCR confidence');
    else if (confidence < rowThreshold) reasons.push('low OCR confidence');
    if (alphaChars < 3) reasons.push('item name too noisy');
    if (digitChars > alphaChars) reasons.push('item name looks misread');
  }
  return { blocked: reasons.length > 0, reasons, confidence };
};
const buildReportManifest = (jobId, token) => {
  const root = "https://primary-production-87e8.up.railway.app".replace(/\/+$/, '');
  const base = root + '/webhook/owner-import-report-bulk-v1?job=' + encodeURIComponent(jobId) + '&token=' + encodeURIComponent(token);
  return {
    summary_url: base + '&kind=summary',
    valid_url: base + '&kind=valid',
    ambiguous_url: base + '&kind=ambiguous',
    invalid_url: base + '&kind=invalid',
    applied_url: base + '&kind=applied',
  };
};

const parseMode = String(meta.parse_mode || 'sheet');
const jobId = String(meta.job_id || '');
const reportToken = String(meta.report_token || '');
const documentConfidence = normalizeConfidence(inputRows.find((row) => row.document_confidence !== undefined)?.document_confidence ?? null);
const documentThreshold = 0.88;
const rowThreshold = 0.9;
const maxRows = parseMode === 'sheet' ? 10000 : 200;
const rawRows = parseMode === 'sheet' ? inputRows.map(mapSheetRecord) : inputRows;
const summary = {
  total_rows: rawRows.length,
  valid_rows: 0,
  invalid_rows: 0,
  ambiguous_rows: 0,
  matched_rows: 0,
  new_rows: 0,
  duplicate_rows: 0,
  skipped_duplicates: 0,
  has_blockers: false,
  document_reasons: [],
};
if (parseMode !== 'sheet') {
  if (documentConfidence === null) summary.document_reasons.push('missing document OCR confidence');
  else if (documentConfidence < documentThreshold) summary.document_reasons.push('low document OCR confidence');
}
if (rawRows.length > maxRows) {
  return [{ json: { ...meta, worker_result: 'too_many_rows', body_text: parseMode === 'sheet' ? 'This bulk job has ' + rawRows.length + ' rows, which is above the current 10,000-row limit. Split the file and upload again.' : 'This OCR import is too large for safe onboarding. Please use XLS, XLSX, CSV, or a public Google Sheets link for large catalogs.' } }];
}
if (!rawRows.length) {
  return [{ json: { ...meta, worker_result: 'empty_import', body_text: 'I could not extract any inventory rows from that bulk import. Please correct the file and try again.' } }];
}

const grouped = new Map();
rawRows.forEach((row, index) => {
  const key = String(row.sku || '').trim().toUpperCase() || normalizeName(row.item_name || '');
  const list = grouped.get(key) || [];
  list.push({ row, index });
  grouped.set(key, list);
});

const duplicateInfo = new Map();
for (const entries of grouped.values()) {
  if (entries.length < 2) continue;
  const comparable = entries.map(({ row }) => JSON.stringify({
    item_name: normalizeName(row.item_name || ''),
    sku: String(row.sku || '').trim().toUpperCase(),
    price: row.price ?? null,
    stock: row.stock ?? null,
    unit: normalizeName(row.unit || ''),
    category: normalizeName(row.category || ''),
    brand: normalizeName(row.brand || ''),
  }));
  if (new Set(comparable).size === 1) {
    entries.slice(1).forEach(({ index }) => duplicateInfo.set(index, { kind: 'skip', reason: 'duplicate row collapsed' }));
    summary.skipped_duplicates += entries.length - 1;
  } else {
    entries.forEach(({ index }) => duplicateInfo.set(index, { kind: 'block', reason: 'conflicting duplicate rows in import batch' }));
    summary.duplicate_rows += entries.length;
    summary.has_blockers = true;
  }
}

const inventoryRows = inventory.map((row) => ({
  ...row,
  normalized_name: normalizeName(row.item_name || ''),
  normalized_sku: String(row.sku || '').trim().toUpperCase(),
  is_active: row.is_active !== false,
}));
const reservedSkus = new Set();
const stagedRows = [];

for (let index = 0; index < rawRows.length; index += 1) {
  const row = rawRows[index];
  const duplicate = duplicateInfo.get(index);
  if (duplicate?.kind === 'skip') continue;
  const assessment = assessRow(row, parseMode, rowThreshold);
  const base = {
    row_no: index + 1,
    chunk_no: Math.floor(index / 250) + 1,
    raw_payload: row,
    normalized_payload: row,
    match_status: 'invalid',
    target_inventory_id: null,
    target_sku: '',
    target_item_name: '',
    error_reason: '',
    review_reason: '',
    row_hash: [normalizeName(row.item_name), String(row.sku || '').trim().toUpperCase(), row.price ?? '', row.stock ?? '', normalizeName(row.unit || ''), normalizeName(row.category || ''), normalizeName(row.brand || '')].join('|'),
    apply_status: 'blocked',
    suggested_sku: '',
  };
  if (duplicate?.kind === 'block') {
    stagedRows.push({ ...base, match_status: 'ambiguous', review_reason: duplicate.reason });
    summary.ambiguous_rows += 1;
    continue;
  }
  if (summary.document_reasons.length || assessment.blocked) {
    stagedRows.push({ ...base, match_status: 'invalid', error_reason: [...summary.document_reasons, ...assessment.reasons].filter(Boolean).join('; ') });
    summary.invalid_rows += 1;
    summary.has_blockers = true;
    continue;
  }
  const normalizedSku = String(row.sku || '').trim().toUpperCase();
  const normalizedName = normalizeName(row.item_name || '');
  let matches = [];
  if (normalizedSku) matches = inventoryRows.filter((item) => item.normalized_sku === normalizedSku);
  if (!matches.length) matches = inventoryRows.filter((item) => item.normalized_name === normalizedName);
  if (matches.length === 1) {
    stagedRows.push({ ...base, match_status: 'matched', target_sku: String(matches[0].sku || ''), target_item_name: String(matches[0].item_name || ''), review_reason: matches[0].is_active ? '' : 'reactivate matched inactive item', apply_status: 'pending' });
    summary.valid_rows += 1;
    summary.matched_rows += 1;
    continue;
  }
  if (!matches.length) {
    const fuzzy = inventoryRows
      .map((item) => ({ item, score: scoreCandidate(normalizedName, item.normalized_name) }))
      .filter((entry) => entry.score >= 0.58)
      .sort((left, right) => right.score - left.score)
      .slice(0, 5);
    if (fuzzy.length === 1 && fuzzy[0].score >= 0.8) {
      stagedRows.push({ ...base, match_status: 'matched', target_sku: String(fuzzy[0].item.sku || ''), target_item_name: String(fuzzy[0].item.item_name || ''), review_reason: 'matched similar existing item', apply_status: 'pending' });
      summary.valid_rows += 1;
      summary.matched_rows += 1;
      continue;
    }
    if (fuzzy.length > 1) {
      stagedRows.push({ ...base, match_status: 'ambiguous', review_reason: fuzzy.map((entry) => entry.item.item_name).join(', ') });
      summary.ambiguous_rows += 1;
      summary.has_blockers = true;
      continue;
    }
  } else if (matches.length > 1) {
    stagedRows.push({ ...base, match_status: 'ambiguous', review_reason: matches.map((entry) => entry.item_name).join(', ') });
    summary.ambiguous_rows += 1;
    summary.has_blockers = true;
    continue;
  }
  const suggestedSku = row.sku ? String(row.sku).trim().toUpperCase() : buildSku(row.item_name, inventoryRows, reservedSkus);
  stagedRows.push({ ...base, match_status: 'new', suggested_sku: suggestedSku, apply_status: 'pending' });
  summary.valid_rows += 1;
  summary.new_rows += 1;
