  const itemName = row.normalized_payload?.item_name || row.raw_payload?.item_name || row.raw_payload?.raw_line || 'row';
  if (row.match_status === 'matched') return '- Match: ' + itemName + ' -> ' + (row.target_item_name || row.target_sku || 'existing item');
  if (row.match_status === 'new') return '- New: ' + itemName + ' (SKU ' + row.suggested_sku + ')';
  if (row.match_status === 'ambiguous') return '- Review: ' + itemName + ' -> ' + row.review_reason;
  return '- Invalid: ' + itemName + (row.error_reason ? ' -> ' + row.error_reason : '');
});

return [{
  json: {
    ...meta,
    has_store_id: schema.has_store_id === true || schema.has_store_id === 'true' || schema.has_store_id === 't' || schema.has_store_id === 1,
    worker_result: 'staged',
    summary,
    staged_rows: stagedRows,
    document_confidence: documentConfidence,
    report_manifest: manifest,
    preview_lines: previewLines,
  },
