const row = $input.first().json || {};
const meta = $('Prepare Bulk Stage').first().json || $('Determine Worker Source').first().json || {};
const summary = (() => {
  const raw = row.summary_json;
  if (!raw) return meta.summary || {};
  if (typeof raw === 'object') return raw;
  try { return JSON.parse(raw); } catch { return meta.summary || {}; }
})();
const reportManifest = (() => {
  const raw = row.report_manifest_json;
  if (!raw) return meta.report_manifest || {};
  if (typeof raw === 'object') return raw;
  try { return JSON.parse(raw); } catch { return meta.report_manifest || {}; }
})();
const testMode = meta.test_mode === true;
const makeText = (body) => ({ chat_id: meta.chat_id || '', message_type: 'text', body_text: body, test_mode: testMode });
const makeButtons = (body, buttons) => ({ chat_id: meta.chat_id || '', message_type: 'button', body_text: body, buttons, test_mode: testMode });
const result = String(row.result || meta.worker_result || 'failed');
