  const summaryLines = [
    'Bulk import review for ' + fileLabel,
    '',
    'Total rows: ' + Number(summary.total_rows || 0),
    'Valid rows: ' + Number(summary.valid_rows || 0) + ' (new ' + Number(summary.new_rows || 0) + ', matched ' + Number(summary.matched_rows || 0) + ')',
    'Ambiguous rows: ' + Number(summary.ambiguous_rows || 0),
    'Invalid rows: ' + Number(summary.invalid_rows || 0),
  ];
  if (reportManifest.summary_url) summaryLines.push('', 'Summary report: ' + reportManifest.summary_url);
  if (reportManifest.ambiguous_url && Number(summary.ambiguous_rows || 0) > 0) summaryLines.push('Ambiguous rows: ' + reportManifest.ambiguous_url);
  if (reportManifest.invalid_url && Number(summary.invalid_rows || 0) > 0) summaryLines.push('Invalid rows: ' + reportManifest.invalid_url);
  if (Number(summary.valid_rows || 0) > 0) {
    return [{ json: makeButtons(summaryLines.join('\n'), [
      { id: 'owner_bulk_apply__' + String(row.job_id || meta.job_id || ''), title: 'Apply Valid Rows' },
      { id: 'owner_bulk_cancel__' + String(row.job_id || meta.job_id || ''), title: 'Cancel Import' },
      { id: 'owner_catalog_import', title: 'Upload Corrected File' },
    ]) }];
  }
  return [{ json: makeButtons(summaryLines.join('\n') + '\n\nNo valid rows are ready to apply yet.', [
    { id: 'owner_catalog_import', title: 'Upload Corrected File' },
    { id: 'owner_bulk_cancel__' + String(row.job_id || meta.job_id || ''), title: 'Cancel Import' },
  ]) }];
}

return [{ json: makeText('Bulk import is ready for review.') }];

